INSERT INTO "hyundai-ventas".contenido_narrativo VALUES ('a66037b3-47a0-4582-9c32-f533289b1bc5', 'e31bb0d2-7f4d-4caa-b2a9-becf42a8fde0', 'Hyundai', 'argumento_venta', 'HB20 — seguridad como diferencial', 'Las 3 versiones incluyen 6 airbags de serie. La versión Platinum Safety suma el paquete ADAS completo: frenado autónomo de emergencia, asistente de mantenimiento de carril y alerta de tráfico cruzado trasero — un argumento fuerte para compradores con foco en seguridad familiar.', NULL, NULL, 'https://agnhyundai.com.ar/hb20/', NULL, NULL, 'true', '2026-07-13T14:43:56.710875+00:00', '2026-07-13T14:43:56.710875+00:00');
