CREATE TABLE IF NOT EXISTS "hyundai-ventas".modelos (
  id uuid DEFAULT extensions.gen_random_uuid() NOT NULL,
  marca text DEFAULT 'Hyundai'::text NOT NULL,
  modelo text NOT NULL,
  version text NOT NULL,
  anio integer,
  precio numeric(14,2),
  moneda text DEFAULT 'ARS'::text,
  vigente_desde date,
  motor text,
  potencia_hp integer,
  torque_nm integer,
  transmision text,
  traccion text,
  consumo_l_100km numeric(5,2),
  equipamiento jsonb,
  colores_disponibles ARRAY,
  imagen_url text,
  galeria_urls ARRAY,
  video_url text,
  ficha_pdf_url text,
  ficha_pdf_extraida jsonb,
  activo boolean DEFAULT true,
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now(),
  PRIMARY KEY (id),
  CONSTRAINT modelos_marca_modelo_version_anio_key UNIQUE (marca),
  CONSTRAINT modelos_marca_modelo_version_anio_key UNIQUE (modelo),
  CONSTRAINT modelos_marca_modelo_version_anio_key UNIQUE (version),
  CONSTRAINT modelos_marca_modelo_version_anio_key UNIQUE (anio),
  CONSTRAINT "46908_48498_1_not_null" CHECK (id IS NOT NULL),
  CONSTRAINT "46908_48498_2_not_null" CHECK (marca IS NOT NULL),
  CONSTRAINT "46908_48498_3_not_null" CHECK (modelo IS NOT NULL),
  CONSTRAINT "46908_48498_4_not_null" CHECK (version IS NOT NULL)
);
CREATE INDEX idx_modelos_modelo ON "hyundai-ventas".modelos USING btree (modelo);
CREATE INDEX idx_modelos_activo ON "hyundai-ventas".modelos USING btree (activo) WHERE (activo = true);

