CREATE OR REPLACE FUNCTION "hyundai-ventas".set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
  new.updated_at = now();
  return new;
end;
$function$
;
CREATE OR REPLACE FUNCTION "hyundai-ventas".match_contenido_narrativo(query_embedding vector, match_threshold double precision DEFAULT 0.75, match_count integer DEFAULT 5)
 RETURNS TABLE(id uuid, modelo_id uuid, tipo text, titulo text, contenido text, similarity double precision)
 LANGUAGE plpgsql
AS $function$
begin
  return query
  select
    c.id,
    c.modelo_id,
    c.tipo,
    c.titulo,
    c.contenido,
    1 - (c.embedding <=> query_embedding) as similarity
  from "hyundai-ventas".contenido_narrativo c
  where c.activo = true
    and 1 - (c.embedding <=> query_embedding) > match_threshold
  order by c.embedding <=> query_embedding
  limit match_count;
end;
$function$
;

CREATE TRIGGER trg_agnmemory_updated_at BEFORE UPDATE ON "hyundai-ventas"."agnMemory" FOR EACH ROW EXECUTE FUNCTION "hyundai-ventas".set_updated_at();

CREATE TRIGGER trg_modelos_updated_at BEFORE UPDATE ON "hyundai-ventas".modelos FOR EACH ROW EXECUTE FUNCTION "hyundai-ventas".set_updated_at();

CREATE TRIGGER trg_contenido_updated_at BEFORE UPDATE ON "hyundai-ventas".contenido_narrativo FOR EACH ROW EXECUTE FUNCTION "hyundai-ventas".set_updated_at();
